// v7 — cursor-based pagination + diagnostic output via webhook response
try {
  const cfg = $input.first().json;
  if (!cfg.apiKey) return [{ json: { error: 'N8N_API_KEY is empty' } }];
  const BASE = 'https://mmurawala.app.n8n.cloud/api/v1';
  const GW = 'https://mmurawala.app.n8n.cloud/webhook/orchestrate-v2';
  const headers = { 'X-N8N-API-KEY': cfg.apiKey };
  const gwHeaders = { 'Content-Type': 'application/json', 'x-api-key': cfg.masterKey };

  // Helper: fetch all rows from a DataTable using cursor-based pagination
  async function fetchAllRows(tableId) {
    let allRows = [];
    let cursor = null;
    let page = 0;
    while (true) {
      let url = `${BASE}/data-tables/${tableId}/rows?limit=250`;
      if (cursor) url += `&cursor=${encodeURIComponent(cursor)}`;
      const resp = await this.helpers.httpRequest({ method: 'GET', url, headers });
      const rows = resp.data || resp || [];
      if (Array.isArray(rows)) {
        allRows = allRows.concat(rows);
      }
      page++;
      // Check for nextCursor in response
      if (resp.nextCursor) {
        cursor = resp.nextCursor;
      } else {
        break;
      }
      // Safety valve
      if (page > 10) break;
    }
    return { rows: allRows, pages: page };
  }

  // 1. Fetch enabled domains (api_registry_v2 — 66 rows, fits in one page)
  const regResp = await this.helpers.httpRequest({ method: 'GET', url: `${BASE}/data-tables/8uXPK6pD52xG90Y0/rows?limit=250`, headers });
  const regRows = regResp.data || regResp || [];
  const domains = (Array.isArray(regRows) ? regRows : []).filter(r => String(r.enabled) === 'true');

  // 2. Fetch ALL actions (action_map_v2 — 401 rows, needs pagination)
  const actionResult = await fetchAllRows.call(this, 'nTBOiE9byj3KcHVQ');
  const allActions = actionResult.rows;
  const enabledActions = allActions.filter(a => String(a.enabled) === 'true');

  // 3. Build catalog (grouped by category)
  const categoryMap = {};
  for (const d of domains) {
    const cat = (d.category || 'OTHER').toUpperCase();
    if (!categoryMap[cat]) categoryMap[cat] = [];
    const acts = enabledActions.filter(a => a.api_name === d.api_name).map(a => a.action).sort();
    if (acts.length > 0) categoryMap[cat].push(d.api_name + '(' + acts.join(',') + ')');
  }
  const ORDER = ['AI','CRM','PRODUCTIVITY','MARKETING','ANALYTICS','CMS','CREATIVE','DEPLOYMENT'];
  let catalog = "Execute any API action through the gateway. Input: domain (string), action (string), client (string - 'kahuna' or 'ascend'), params (object - action-specific parameters).\n\nAVAILABLE DOMAINS AND ACTIONS (call directly \u2014 no need for list_domains/list_actions/get_action_schema first):\n\n";
  for (const cat of ORDER) {
    if (categoryMap[cat] && categoryMap[cat].length > 0) {
      catalog += cat + ': ' + categoryMap[cat].join(' | ') + '\n\n';
      delete categoryMap[cat];
    }
  }
  for (const cat of Object.keys(categoryMap).sort()) {
    if (categoryMap[cat].length > 0) catalog += cat + ': ' + categoryMap[cat].join(' | ') + '\n\n';
  }
  catalog += "PARAM HINTS: For 'passthrough' domains (AI, Apollo, Gong, Semrush, Vercel, etc), params go directly as the API body. For 'handler' domains (HubSpot, Google, Slack, etc), check get_action_schema if unsure about required params.";

  // 4. GET current MCP Gateway workflow to compare
  const wf = await this.helpers.httpRequest({ method: 'GET', url: `${BASE}/workflows/42BsiQ2R7nstxydY`, headers });
  let currentDesc = '';
  for (const node of wf.nodes) {
    if (node.parameters && node.parameters.name === 'execute_action') {
      currentDesc = node.parameters.description || '';
      break;
    }
  }

  if (currentDesc === catalog) {
    return [{ json: { success: true, skipped: true, reason: 'catalog_unchanged', catalog_length: catalog.length, domains: domains.length, actions: enabledActions.length, action_pages: actionResult.pages } }];
  }

  // 5. Update the execute_action description in the gateway workflow
  const cleanNodes = wf.nodes.map(n => {
    const clean = { parameters: {...n.parameters}, name: n.name, type: n.type, typeVersion: n.typeVersion, position: n.position };
    if (n.webhookId) clean.webhookId = n.webhookId;
    return clean;
  });
  for (const node of cleanNodes) {
    if (node.parameters && node.parameters.name === 'execute_action') {
      node.parameters.description = catalog;
      break;
    }
  }

  let updateSuccess = false;
  let updateError = '';
  try {
    await this.helpers.httpRequest({
      method: 'PUT',
      url: `${BASE}/workflows/42BsiQ2R7nstxydY`,
      headers: { ...headers, 'Content-Type': 'application/json' },
      body: { name: wf.name, nodes: cleanNodes, connections: wf.connections, settings: wf.settings }
    });
    updateSuccess = true;
  } catch(e) {
    updateError = e.message;
    // Fallback: Slack alert
    try {
      await this.helpers.httpRequest({
        method: 'POST', url: GW, headers: gwHeaders,
        body: { domain: 'slack', action: 'send', client: 'ascend', params: {
          channel: 'all-ascendgtm',
          text: '*PLATFORM_CATALOG_SYNC*: Catalog changed (' + domains.length + ' domains, ' + enabledActions.length + ' actions, ' + catalog.length + ' chars) but auto-update failed: ' + updateError + '. Manual update needed.'
        }}
      });
    } catch(e2) {}
  }

  // 6. Log
  try {
    await this.helpers.httpRequest({
      method: 'POST', url: GW, headers: gwHeaders,
      body: { domain: 'handover', action: 'log_change', client: 'ascend', params: {
        workflow_name: 'PLATFORM_CATALOG_SYNC',
        change_type: updateSuccess ? 'catalog_refresh' : 'catalog_refresh_failed',
        description: (updateSuccess ? 'Auto-refreshed' : 'Generated but PUT failed') + ': ' + domains.length + ' domains, ' + enabledActions.length + ' actions, ' + catalog.length + ' chars',
        date: new Date().toISOString()
      }}
    });
  } catch(e) {}

  return [{ json: {
    success: updateSuccess,
    auto_updated: updateSuccess,
    update_error: updateError || undefined,
    domains: domains.length,
    total_actions_fetched: allActions.length,
    enabled_actions: enabledActions.length,
    action_pages: actionResult.pages,
    catalog_length: catalog.length,
    old_length: currentDesc.length,
    delta: catalog.length - currentDesc.length
  }}];
} catch (err) {
  return [{ json: { success: false, error: err.message, stack: String(err.stack).substring(0, 500) } }];
}
